INSERT INTO compliance_rules (framework_short,rule_id,description,regex_pattern,url_check,severity,citation_url,enforcement_example,rule_type,trigger_pattern,fine_low_gbp,fine_high_gbp,layman_explanation,tamazia_fix_short,service_page_path,pricing_tier,active,sector_relevance,created_at) VALUES
('UAE_PDPL','PDPL_CONTROLLER','Identity and contact of the data controller disclosed before collection','(data controller|controller is|who we are|our (company|details)|registered (office|address))','homepage','P1','https://uaelegislation.gov.ae/en/legislations/1972','UAE PDPL (Federal Decree-Law 45/2021), in force Jan 2022; administrative penalties are being set by the Cabinet via the Executive Regulations.','trigger_then_check','(privacy|personal data|data protection|we collect|your (data|information)|cookie|gdpr|contact (us|form)|newsletter|sign ?up|register|create account)',NULL,NULL,'UAE PDPL Article 13 requires you to tell UAE data subjects who the controller is and how to reach it before you collect their data. Your notice does not make this clear.','Tamazia adds a PDPL-compliant controller-identity and contact block to the privacy notice.','/services/compliance','scale',TRUE,NULL,now()),
('UAE_PDPL','PDPL_PURPOSE','Purposes and legal basis of processing stated','(purpose(s)? (of|for) (processing|collection)|why we (collect|use)|legal basis|lawful basis)','homepage','P1','https://uaelegislation.gov.ae/en/legislations/1972','UAE PDPL Art. 13; penalties via the forthcoming Executive Regulations.','trigger_then_check','(privacy|personal data|data protection|we collect|your (data|information)|cookie|gdpr|contact (us|form)|newsletter|sign ?up|register|create account)',NULL,NULL,'The UAE PDPL requires the purposes and legal basis for processing to be disclosed. Yours are not stated.','Tamazia documents each processing purpose and its PDPL legal basis in the notice.','/services/compliance','scale',TRUE,NULL,now()),
('UAE_PDPL','PDPL_CONSENT','Consent that is freely given, specific, informed and revocable','(consent|you agree|opt[- ]?in|withdraw (your )?consent|revoke)','homepage','P1','https://uaelegislation.gov.ae/en/legislations/1972','UAE PDPL makes consent the default basis; it must be revocable at any time.','trigger_then_check','(privacy|personal data|data protection|we collect|your (data|information)|cookie|gdpr|contact (us|form)|newsletter|sign ?up|register|create account)',NULL,NULL,'Under the UAE PDPL consent is the default basis and must be freely given, specific and revocable at any time. Your site has no compliant consent mechanism.','Tamazia implements a PDPL consent mechanism with an easy withdrawal route.','/services/compliance','scale',TRUE,NULL,now()),
('UAE_PDPL','PDPL_RIGHTS','Data subject rights (access, correction, erasure, restriction, withdraw) disclosed','(right to (access|correct|rectif|erase|delete|restrict|object|withdraw)|your rights|data subject rights)','homepage','P1','https://uaelegislation.gov.ae/en/legislations/1972','UAE PDPL Arts. 13-19 grant access, correction, erasure, restriction and withdrawal rights.','trigger_then_check','(privacy|personal data|data protection|we collect|your (data|information)|cookie|gdpr|contact (us|form)|newsletter|sign ?up|register|create account)',NULL,NULL,'The UAE PDPL gives residents rights to access, correct, erase and restrict their data; your notice does not explain how to exercise them.','Tamazia adds a clear data-subject-rights section with a request route.','/services/compliance','scale',TRUE,NULL,now()),
('UAE_PDPL','PDPL_CROSSBORDER','Cross-border transfer of personal data outside the UAE disclosed','(transfer.{0,30}(outside|abroad|international)|cross[- ]border|outside the (uae|country)|adequate (level|protection))','homepage','P2','https://uaelegislation.gov.ae/en/legislations/1972','UAE PDPL restricts transfers outside the UAE and requires disclosure + safeguards.','trigger_then_check','(privacy|personal data|data protection|we collect|your (data|information)|cookie|gdpr|contact (us|form)|newsletter|sign ?up|register|create account)',NULL,NULL,'If you send UAE residents data abroad (most cloud tools do), the PDPL requires you to disclose it and ensure adequate protection. Your notice is silent.','Tamazia documents your international transfers and the PDPL safeguards.','/services/compliance','scale',TRUE,NULL,now()),
('DIFC_DPL','DIFC_REGISTRATION','Registration with the DIFC Commissioner of Data Protection','(registered with the (difc )?commissioner|difc data protection|commissioner of data protection|notification number)','homepage','P1','https://www.difc.com/business/laws-and-regulations/legal-database/difc-laws/data-protection-law-difc-law-no-5-2020','DIFC DPL No.5 of 2020: registration with the Commissioner is mandatory; failure to notify draws fines up to USD 50,000.','trigger_then_check','(privacy|personal data|data protection|we collect|your (data|information)|cookie|gdpr|contact (us|form)|newsletter|sign ?up|register|create account)',40000,79000,'A DIFC-based controller must register with the Commissioner of Data Protection. There is no sign you have, and non-registration is finable up to USD 50,000.','Tamazia confirms and evidences your DIFC Commissioner registration.','/services/compliance','scale',TRUE,NULL,now()),
('DIFC_DPL','DIFC_NOTICE','Fair-processing privacy notice meeting DIFC DPL Article 29','(privacy (notice|policy)|fair processing|how we (use|process) your data)','homepage','P1','https://www.difc.com/business/laws-and-regulations/legal-database/difc-laws/data-protection-law-difc-law-no-5-2020','DIFC DPL Art. 29 information duties; data-subject-rights breaches are finable up to USD 100,000.','trigger_then_check','(privacy|personal data|data protection|we collect|your (data|information)|cookie|gdpr|contact (us|form)|newsletter|sign ?up|register|create account)',40000,79000,'The DIFC DPL requires a fair-processing notice with the prescribed information. Yours does not meet the DIFC bar.','Tamazia rewrites the notice to DIFC DPL Article 29 standard.','/services/compliance','scale',TRUE,NULL,now()),
('DIFC_DPL','DIFC_RIGHTS','DIFC data subject rights disclosed','(right to (access|rectif|erasure|object|portability)|data subject rights)','homepage','P2','https://www.difc.com/business/registrars-and-commissioners/commissioner-of-data-protection','DIFC DPL grants GDPR-style rights; breach of data-subject rights is the most heavily fined area (up to USD 100,000).','trigger_then_check','(privacy|personal data|data protection|we collect|your (data|information)|cookie|gdpr|contact (us|form)|newsletter|sign ?up|register|create account)',40000,79000,'DIFC residents have GDPR-style data rights; failing to honour or disclose them is the DIFC Commissioner most-fined breach.','Tamazia adds a DIFC-compliant rights section and request workflow.','/services/compliance','scale',TRUE,NULL,now()),
('ADGM_DPR','ADGM_REGISTRATION','Registration with the ADGM Commissioner + GDPR-aligned notice','(adgm|registered with the commissioner|abu dhabi global market)','homepage','P2','https://www.adgm.com/operating-in-adgm/office-of-data-protection','ADGM Data Protection Regulations 2021 require registration and a GDPR-aligned privacy notice for controllers established in ADGM.','trigger_then_check','(privacy|personal data|data protection|we collect|your (data|information)|cookie|gdpr|contact (us|form)|newsletter|sign ?up|register|create account)',40000,79000,'A controller established in ADGM must register and publish a GDPR-aligned notice. There is no evidence you have.','Tamazia confirms ADGM registration and brings the notice to the ADGM standard.','/services/compliance','scale',TRUE,NULL,now()),
('SAUDI_PDPL','SAUDI_NOTICE','Privacy notice: identity, purpose, recipients, risks, rights','(privacy (notice|policy)|who we are|purpose|your rights|personal data)','homepage','P1','https://sdaia.gov.sa/en/SDAIA/about/Documents/Personal%20Data%20English%20V2-23April2023-%20Reviewed-.pdf','Saudi PDPL (in full force 14 Sep 2024); SDAIA fines reach SAR 5,000,000, doubled for repeat offences.','trigger_then_check','(privacy|personal data|data protection|we collect|your (data|information)|cookie|gdpr|contact (us|form)|newsletter|sign ?up|register|create account)',630000,1050000,'Saudi PDPL requires residents to be told the identity, purpose, recipients, risks of not providing data, and their rights. Your notice omits these.','Tamazia builds a Saudi PDPL-compliant privacy notice with all mandated disclosures.','/services/compliance','scale',TRUE,NULL,now()),
('SAUDI_PDPL','SAUDI_CONSENT','Valid consent and an easy withdrawal route','(consent|withdraw (your )?consent|opt[- ]?in)','homepage','P1','https://sdaia.gov.sa/en/Research/Pages/DataProtection.aspx','Saudi PDPL requires consent for most processing; withdrawal must be possible.','trigger_then_check','(privacy|personal data|data protection|we collect|your (data|information)|cookie|gdpr|contact (us|form)|newsletter|sign ?up|register|create account)',630000,1050000,'Saudi PDPL requires a lawful consent basis with the ability to withdraw. Your site lacks a compliant mechanism.','Tamazia implements Saudi PDPL consent capture and withdrawal.','/services/compliance','scale',TRUE,NULL,now()),
('SAUDI_PDPL','SAUDI_MARKETING','Prior consent for marketing communications','(marketing (consent|preferences)|unsubscribe|opt[- ]?out of marketing|consent to (receive|marketing))','homepage','P1','https://sdaia.gov.sa/en/Research/Pages/DataProtection.aspx','SDAIA specifically actioned firms in 2025-26 for sending marketing communications without consent; fines to SAR 5,000,000.','trigger_then_check','(subscribe|newsletter|marketing|email updates|sms|whatsapp)',630000,1050000,'Saudi PDPL requires prior consent for marketing. SDAIA has fined firms in 2025-26 for marketing without it, and your capture has no clear consent.','Tamazia adds PDPL-compliant marketing consent to every capture point.','/services/compliance','scale',TRUE,NULL,now()),
('SAUDI_PDPL','SAUDI_RIGHTS','Data subject rights (access, copy, correction, deletion, withdraw)','(right to (access|correct|delete|withdraw)|request (a )?copy|your rights)','homepage','P2','https://sdaia.gov.sa/en/Research/Pages/DataProtection.aspx','Saudi PDPL grants access, copy, correction, deletion and withdrawal rights.','trigger_then_check','(privacy|personal data|data protection|we collect|your (data|information)|cookie|gdpr|contact (us|form)|newsletter|sign ?up|register|create account)',630000,1050000,'Saudi residents can access, copy, correct, delete their data and withdraw consent; your notice does not explain how.','Tamazia adds a Saudi PDPL rights section and request route.','/services/compliance','scale',TRUE,NULL,now()),
('SAUDI_PDPL','SAUDI_DPO','Data Protection Officer where required + contact','(data protection officer|dpo|privacy@|data protection contact)','homepage','P3','https://sdaia.gov.sa/en/Research/Pages/DataProtection.aspx','Saudi PDPL requires a DPO for entities processing sensitive data at scale or doing cross-border transfers.','trigger_then_check','(privacy|personal data|data protection|we collect|your (data|information)|cookie|gdpr|contact (us|form)|newsletter|sign ?up|register|create account)',630000,1050000,'If you process Saudi sensitive data at scale or transfer cross-border, the PDPL requires a named DPO; no contact is published.','Tamazia appoints/【names a DPO and publishes the contact.','/services/compliance','scale',TRUE,NULL,now()),
('QATAR_PDPPL','QATAR_NOTICE','Transparent privacy notice (identity, purpose, rights)','(privacy (notice|policy)|who we are|purpose|your rights)','homepage','P1','https://www.pwc.com/m1/en/services/consulting/technology/cyber-security/navigating-data-privacy-regulations/qatar-data-protection-law.html','Qatar PDPPL (Law 13/2016); NDPO fines QAR 1,000,000 to QAR 5,000,000 per violation.','trigger_then_check','(privacy|personal data|data protection|we collect|your (data|information)|cookie|gdpr|contact (us|form)|newsletter|sign ?up|register|create account)',220000,1080000,'Qatar PDPPL requires a transparent privacy notice covering identity, purpose and rights. Yours falls short for Qatari residents.','Tamazia builds a Qatar PDPPL-compliant notice.','/services/compliance','scale',TRUE,NULL,now()),
('QATAR_PDPPL','QATAR_CONSENT','Consent and withdrawal of consent','(consent|withdraw (your )?consent|opt[- ]?in)','homepage','P2','https://www.pwc.com/m1/en/services/consulting/technology/cyber-security/navigating-data-privacy-regulations/qatar-data-protection-law.html','Qatar PDPPL requires consent and an objection/withdrawal route; fines up to QAR 5,000,000.','trigger_then_check','(privacy|personal data|data protection|we collect|your (data|information)|cookie|gdpr|contact (us|form)|newsletter|sign ?up|register|create account)',220000,1080000,'Qatar PDPPL requires consent with the ability to object and withdraw; your site has no compliant mechanism.','Tamazia adds Qatar PDPPL consent and withdrawal.','/services/compliance','scale',TRUE,NULL,now()),
('QATAR_PDPPL','QATAR_BREACH','Breach-notification readiness (72 hours to NDPO)','(data breach|incident response|breach notification|security incident)','homepage','P3','https://www.pwc.com/m1/en/services/consulting/technology/cyber-security/navigating-data-privacy-regulations/qatar-data-protection-law.html','Qatar PDPPL requires breach notification to the NDPO within 72 hours.','trigger_then_check','(privacy|personal data|data protection|we collect|your (data|information)|cookie|gdpr|contact (us|form)|newsletter|sign ?up|register|create account)',220000,1080000,'Qatar PDPPL requires breach notification to the NDPO within 72 hours; no incident-response posture is evident.','Tamazia documents a 72-hour breach-notification process.','/services/compliance','scale',TRUE,NULL,now()),
('UAE_DHA','DHA_AD_PERMIT','Medical advertising permit / DHA approval evident','(dha (permit|approval|licen)|moh permit|advertising permit|permit (no|number)|licensed by (the )?dha)','homepage','P1','https://dha.gov.ae/uploads/112021/4d65313d-cb85-41e0-a817-b630d277175c.pdf','The DHA and MOHAP require approval/permits for medical advertising in the UAE; the DHA actions clinics over non-compliant medical ads.','trigger_then_check','(clinic|dental|aesthetic|cosmetic|treatment|botox|filler|implant|surgery|dermatolog|consultant|patient)',NULL,NULL,'A UAE clinic advertising treatments must hold DHA/MOHAP advertising approval. There is no permit reference, which the DHA treats as non-compliant medical advertising.','Tamazia secures and displays the DHA advertising approval and aligns the content.','/services/compliance','scale',TRUE,'{healthcare,dental,wellness,medical}',now()),
('UAE_DHA','DHA_CLAIMS','No exaggerated or unsubstantiated medical claims','(guarantee|guaranteed|painless|100%|best (clinic|doctor)|no risk|permanent (cure|results)|miracle)','homepage','P1','https://dha.gov.ae/uploads/042022/Standards%20for%20Medical%20Advertisement%20Content%20in%20Social%20Media2022433965.pdf','DHA standards require correct, balanced medical statements and ban unsubstantiated claims.','trigger_then_check','(clinic|dental|aesthetic|cosmetic|treatment|botox|filler|implant|surgery|dermatolog)',NULL,NULL,'DHA rules require balanced, evidence-based medical statements. Superlative or guarantee-style claims on your site breach the DHA advertising standards.','Tamazia rewrites medical claims to the DHA balanced-evidence standard.','/services/compliance','scale',TRUE,'{healthcare,dental,wellness,medical}',now()),
('UAE_DHA','DHA_LOGO','No DHA/government logo without written approval','(dha logo|ministry of health logo|government (logo|emblem))','homepage','P3','https://dha.gov.ae/uploads/042022/Standards%20for%20Medical%20Advertisement%20Content%20in%20Social%20Media2022433965.pdf','DHA standards prohibit using the DHA or any government logo without explicit written approval.','trigger_then_check','(clinic|dental|aesthetic|treatment|patient|medical)',NULL,NULL,'Using a DHA or government logo without written approval breaches DHA social-media advertising standards.','Tamazia removes unauthorised government logos or secures the written approval.','/services/compliance','scale',TRUE,'{healthcare,dental,wellness,medical}',now()),
('UAE_RERA','RERA_TRAKHEESI','Valid Trakheesi permit number on every property advertisement','(trakheesi|permit (no|number)|advertis(ing|ement) permit|dld permit)','homepage','P1','https://dubailand.gov.ae/en/eservices/real-estate-ad-permit/','Every Dubai property advertisement must display a valid Trakheesi permit number issued by the DLD/RERA; non-compliant ads are fined and suspended.','trigger_then_check','(for sale|for rent|\baed\b|off[- ]plan|villa|apartment|bedroom|property|listing|sq ?ft)',NULL,NULL,'Every Dubai property advertisement must carry a valid Trakheesi permit number. Your listings show none, which RERA/DLD treats as an unlicensed advertisement subject to fines and takedown.','Tamazia adds the Trakheesi permit number to every listing and wires it into your publishing flow.','/services/compliance','scale',TRUE,'{realestate,real-estate,property}',now()),
('UAE_RERA','RERA_BROKER','Broker/ORN registration number displayed','(orn|broker (no|number|registration)|rera (registration|number)|brn)','homepage','P2','https://dubailand.gov.ae/en/eservices/real-estate-ad-permit/','RERA requires licensed brokers/companies to be identifiable; ads must trace to a registered broker.','trigger_then_check','(for sale|for rent|\baed\b|property|listing|estate agent|broker)',NULL,NULL,'RERA advertising rules require the listing to trace to a registered broker/ORN. Yours does not display it.','Tamazia adds your RERA ORN/broker registration to listings.','/services/compliance','scale',TRUE,'{realestate,real-estate,property}',now()),
('UAE_CONSUMER','UAE_PRICE','Clear, all-inclusive pricing for UAE consumers','(total price|inclusive of (vat|tax)|all[- ]inclusive|price includes|vat included)','homepage','P2','https://uaelegislation.gov.ae/en/legislations/1530','UAE Consumer Protection Law (Federal Law 15/2020) requires clear, honest pricing; the Ministry of Economy penalises misleading prices.','trigger_then_check','(\baed\b|buy now|add to (cart|basket)|checkout|price|shop)',NULL,NULL,'UAE consumer law requires clear, all-inclusive pricing. Your displayed prices are not clearly inclusive, which the Ministry of Economy can penalise.','Tamazia displays all-inclusive prices and removes hidden-fee patterns for UAE buyers.','/services/compliance','scale',TRUE,'{ecommerce,retail,hospitality}',now()),
('UAE_ECOMMERCE','UAE_TRADER_ID','Trader identity + terms on UAE online store','(trade licen|company registration|registered (in|office)|terms (and conditions|of (sale|service))|return policy)','homepage','P2','https://uaelegislation.gov.ae/en/legislations/2402','UAE e-commerce rules (Federal Decree-Law 46/2021) require trader identification and clear terms on online stores serving UAE consumers.','trigger_then_check','(\baed\b|add to (cart|basket)|checkout|online (store|shop)|buy now)',NULL,NULL,'A UAE online store must identify the trader and publish clear terms and a return policy. Yours are missing or unclear.','Tamazia adds UAE trader-identity, terms and returns to the store.','/services/compliance','scale',TRUE,'{ecommerce,retail}',now())
